// HTML nümunəsi:
/*
<div id="outfitElement">Geyimlər yüklənir...</div>
<button id="loadBtn">Geyimləri yüklə</button>
*/

// API-dən məlumat almaq
const outfitElement = document.getElementById("outfitElement");
const loadBtn = document.getElementById("loadBtn");

loadBtn.addEventListener("click", async () => {
  try {
    outfitElement.classList.add("loading");
    const response = await fetch("https://api.example.com/outfits");
    const data = await response.json();
    outfitElement.textContent = data.outfits || "Yeni geyimlər!";
    outfitElement.classList.remove("loading");
    outfitElement.classList.add("loaded");
  } catch (error) {
    outfitElement.textContent = "Xəta: Geyimlər yüklənmədi!";
  }
});

// POST sorğusu ilə yeni geyim əlavə etmək
loadBtn.addEventListener("click", async () => {
  try {
    const response = await fetch("https://api.example.com/add-outfit", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ "name": "Trendy Shirt", "type": "Summer" })
    });
    const data = await response.json();
    outfitElement.textContent = data.message || "Geyim əlavə edildi!";
  } catch (error) {
    outfitElement.textContent = "Xəta!";
  }
});

